using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O — use async throughout.
    async Task FindProducts(ProductContext ctx)
    {
        // Safe: we configured HasDiscriminator<string>("Discriminator") so existing
        // documents and direct SQL queries that reference c.Discriminator still work.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

